import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface SprintData {
  sprint: {
    name: string;
    duration: string;
    totalStoryPoints: number;
    completedStoryPoints: number;
  };
  burndown: {
    day: string;
    remainingPoints: number;
  }[];
}

export default function Widget() {
  const sprintData = response.data as SprintData;
  const { sprint, burndown } = sprintData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#121212', color: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600}>
              {sprint.name}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Duration: {sprint.duration}
            </Typography>
            <Typography variant="body1" fontWeight={500} sx={{ color: '#FFC107', mt: 1 }}>
              Completed: {sprint.completedStoryPoints}/{sprint.totalStoryPoints} Story Points
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: burndown.map(day => day.remainingPoints),
                  color: '#007BFF',
                  curve: 'linear',
                  label: 'Remaining Points',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: burndown.map(day => day.day),
                  id: 'days',
                },
              ]}
              yAxis={[{ id: 'points' }]}
            >
              <ChartsClipPath id={clipPathId} />
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="days"
                tickLabelStyle={{ fontSize: 10, fill: '#FFFFFF' }}
              />
              <ChartsYAxis
                axisId="points"
                tickLabelStyle={{ fontSize: 10, fill: '#FFFFFF' }}
              />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
